import { newFieldList, resolveMessageType, } from "./field.js";
import { applyPartialMessage } from "./partial.js";
import { LongType, ScalarType, scalarEquals, scalarZeroValue, } from "./scalar.js";
import { binaryReadMessage, binaryWriteMessage, binaryMakeReadOptions, binaryMakeWriteOptions, } from "./binary.js";
import { jsonReadMessage, jsonWriteMessage, jsonMakeReadOptions, jsonMakeWriteOptions, } from "./json.js";
import { throwSanitizeKey } from "./names.js";
import { enumZeroValue } from "./enum.js";
/**
 * createMessageType creates a new message type.
 *
 * The argument `packedByDefault` specifies whether fields that do not specify
 * `packed` should be packed (proto3) or unpacked (proto2).
 */
export function createMessageType(params, exts) {
    const { fields: fieldsSource, typeName, packedByDefault, delimitedMessageEncoding, fieldWrapper, } = params;
    const fields = newFieldList(fieldsSource, packedByDefault);
    const mt = {
        typeName,
        fields,
        fieldWrapper,
        create(partial) {
            const message = Object.create(null);
            applyPartialMessage(partial, message, fields);
            return message;
        },
        createComplete(partial) {
            const message = createCompleteMessage(fields);
            applyPartialMessage(partial, message, fields);
            return message;
        },
        equals(a, b) {
            return compareMessages(fields, a, b);
        },
        clone(a) {
            if (a == null) {
                return a;
            }
            return cloneMessage(a, fields);
        },
        fromBinary(bytes, options) {
            const message = {};
            if (bytes && bytes.length) {
                const opt = binaryMakeReadOptions(options);
                binaryReadMessage(message, fields, opt.readerFactory(bytes), bytes.byteLength, opt, delimitedMessageEncoding ?? false);
            }
            return message;
        },
        fromJson(jsonValue, options) {
            const message = {};
            if (jsonValue != null) {
                const opts = jsonMakeReadOptions(options);
                jsonReadMessage(fields, typeName, jsonValue, opts, message);
            }
            return message;
        },
        fromJsonString(jsonString, options) {
            let json = null;
            if (jsonString) {
                try {
                    json = JSON.parse(jsonString);
                }
                catch (e) {
                    throw new Error(`cannot decode ${typeName} from JSON: ${e instanceof Error ? e.message : String(e)}`, { cause: e });
                }
            }
            return mt.fromJson(json, options);
        },
        toBinary(a, options) {
            if (a == null)
                return new Uint8Array(0);
            const opt = binaryMakeWriteOptions(options);
            const writer = opt.writerFactory();
            binaryWriteMessage(a, fields, writer, opt);
            return writer.finish();
        },
        toJson(a, options) {
            const opt = jsonMakeWriteOptions(options);
            return jsonWriteMessage(a, fields, opt);
        },
        toJsonString(a, options) {
            const value = mt.toJson(a, options);
            return JSON.stringify(value, null, options?.prettySpaces ?? 0);
        },
        ...(exts ?? {}),
    };
    return mt;
}
// compareMessages compares two messages for equality.
export function compareMessages(fields, a, b) {
    if (a == null && b == null) {
        return true;
    }
    if (a === b) {
        return true;
    }
    if (!a || !b) {
        return false;
    }
    return fields.byMember().every((m) => {
        const va = a[m.localName];
        const vb = b[m.localName];
        if (m.repeated) {
            if ((va?.length ?? 0) !== (vb?.length ?? 0)) {
                return false;
            }
            if (!va?.length) {
                return true;
            }
            switch (m.kind) {
                case "message": {
                    const messageType = resolveMessageType(m.T);
                    return va.every((a, i) => messageType.equals(a, vb[i]));
                }
                case "scalar":
                    return va.every((a, i) => scalarEquals(m.T, a, vb[i]));
                case "enum":
                    return va.every((a, i) => scalarEquals(ScalarType.INT32, a, vb[i]));
            }
            throw new Error(`repeated cannot contain ${m.kind}`);
        }
        switch (m.kind) {
            case "message":
                return resolveMessageType(m.T).equals(va, vb);
            case "enum":
                return scalarEquals(ScalarType.INT32, va, vb);
            case "scalar":
                return scalarEquals(m.T, va, vb);
            case "oneof": {
                if (va?.case !== vb?.case) {
                    return false;
                }
                if (va == null) {
                    return true;
                }
                const s = m.findField(va.case);
                if (s === undefined) {
                    return true;
                }
                switch (s.kind) {
                    case "message": {
                        const messageType = resolveMessageType(s.T);
                        return messageType.equals(va.value, vb.value);
                    }
                    case "enum":
                        return scalarEquals(ScalarType.INT32, va.value, vb.value);
                    case "scalar":
                        return scalarEquals(s.T, va.value, vb.value);
                }
                throw new Error(`oneof cannot contain ${s.kind}`);
            }
            case "map": {
                const ma = va ?? {};
                const mb = vb ?? {};
                const keys = Object.keys(ma).concat(Object.keys(mb));
                switch (m.V.kind) {
                    case "message": {
                        const messageType = resolveMessageType(m.V.T);
                        return keys.every((k) => messageType.equals(ma[k], mb[k]));
                    }
                    case "enum":
                        return keys.every((k) => scalarEquals(ScalarType.INT32, ma[k], mb[k]));
                    case "scalar": {
                        const scalarType = m.V.T;
                        return keys.every((k) => scalarEquals(scalarType, ma[k], mb[k]));
                    }
                }
            }
        }
    });
}
export function cloneMessage(message, fields) {
    if (message == null) {
        return null;
    }
    const clone = Object.create(null);
    applyPartialMessage(message, clone, fields, true);
    return clone;
}
/**
 * createCompleteMessage recursively builds a message filled with zero values based on the given FieldList.
 */
export function createCompleteMessage(fields) {
    const message = {};
    for (const field of fields.byMember()) {
        const { localName, kind: fieldKind } = field;
        throwSanitizeKey(localName);
        switch (fieldKind) {
            case "oneof":
                message[localName] = Object.create(null);
                message[localName].case = undefined;
                break;
            case "scalar":
                if (field.repeated) {
                    message[localName] = [];
                }
                else {
                    message[localName] = scalarZeroValue(field.T, LongType.BIGINT);
                }
                break;
            case "enum":
                message[localName] = field.repeated ? [] : enumZeroValue(field.T);
                break;
            case "message": {
                // oneofs are handled above
                if (field.oneof) {
                    break;
                }
                if (field.repeated) {
                    message[localName] = [];
                    break;
                }
                const messageType = resolveMessageType(field.T);
                message[localName] =
                    messageType.fieldWrapper ?
                        messageType.fieldWrapper.unwrapField(null)
                        : createCompleteMessage(messageType.fields);
                break;
            }
            case "map":
                message[localName] = Object.create(null);
                break;
            default:
                field;
        }
    }
    return message;
}
